/* CompTIA AI Fundamentals :: content/quiz2.js — question bank for Domain 2 (100 items). */
window.AIFUND = window.AIFUND || {}; AIFUND.questions = AIFUND.questions || [];
AIFUND.questions.push(
{ id:"D2-001", domain:2, obj:"2.1", diff:"easy", q:"A marketing coordinator needs to brainstorm ten possible headlines for a new product page. Why is this a GOOD fit for a general-purpose AI chatbot?", options:["It produces many varied ideas quickly for a human to refine","It guarantees each headline is legally cleared for use","It removes the need for a human to review the output","It knows exactly which headline will sell the most"], answer:0, explain:"<strong>It produces many varied ideas quickly for a human to refine</strong> is why brainstorming suits AI: generating lots of low-stakes creative options fast, with a person choosing and polishing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees each headline is legally cleared for use</b>: an AI cannot clear legal or trademark issues, and that still needs human or legal review.</span><span class='qd'><b>It removes the need for a human to review the output</b>: brainstorming is useful precisely because a human still selects and refines, so review is not removed.</span><span class='qd'><b>It knows exactly which headline will sell the most</b>: predicting real sales performance requires testing and data the model does not have.</span>" },
{ id:"D2-002", domain:2, obj:"2.1", diff:"easy", q:"Which task is generally the POOREST fit for a public AI chatbot?", options:["Drafting a friendly reminder email to a colleague","Making the final decision to deny someone's medical claim on its own","Summarizing the main points of a long article","Suggesting synonyms for a word in a report"], answer:1, explain:"<strong>Making the final decision to deny someone's medical claim on its own</strong> is a poor fit because a high-stakes, life-affecting decision needs human judgment, accountability, and context the tool lacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Drafting a friendly reminder email to a colleague</b>: a low-stakes draft that a person reviews is a good, common use.</span><span class='qd'><b>Summarizing the main points of a long article</b>: summarizing text is a strong use case when the reader verifies key facts.</span><span class='qd'><b>Suggesting synonyms for a word in a report</b>: word-choice help is a simple, low-risk assist.</span>" },
{ id:"D2-003", domain:2, obj:"2.1", diff:"easy", q:"A student wants AI to help them understand a confusing chapter by explaining it in simpler terms. Why does this work well?", options:["The AI can grade the student's final exam for them","The student no longer needs to read the chapter at all","Explaining and rephrasing known material is a core strength of language models","The AI has personally read every textbook ever printed"], answer:2, explain:"<strong>Explaining and rephrasing known material is a core strength of language models</strong>, so restating a concept in plain language is a very good fit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI can grade the student's final exam for them</b>: grading an official exam is a separate, higher-stakes task not implied here.</span><span class='qd'><b>The student no longer needs to read the chapter at all</b>: a simpler explanation supports understanding but does not replace engaging with the material.</span><span class='qd'><b>The AI has personally read every textbook ever printed</b>: models learn from patterns in training data, not by reading specific books on demand, and may not have the exact chapter.</span>" },
{ id:"D2-004", domain:2, obj:"2.1", diff:"easy", q:"Why is asking a general AI chatbot for today's exact stock price of a company usually a POOR use of the tool?", options:["Stock prices are illegal for AI to discuss","The chatbot always refuses financial questions","Stock prices never change during the day","The chatbot may not have live data and can state an outdated or made-up figure"], answer:3, explain:"<strong>The chatbot may not have live data and can state an outdated or made-up figure</strong> because many models are not connected to real-time markets and will still answer confidently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stock prices are illegal for AI to discuss</b>: discussing prices is not illegal; the issue is data freshness and accuracy.</span><span class='qd'><b>The chatbot always refuses financial questions</b>: chatbots often answer such questions, which is part of the risk.</span><span class='qd'><b>Stock prices never change during the day</b>: prices change constantly, which is exactly why stale data is a problem.</span>" },
{ id:"D2-005", domain:2, obj:"2.1", diff:"medium", q:"A team is deciding whether to use AI to write first drafts of internal newsletter articles that an editor will review. Which factor makes this an APPROPRIATE use?", options:["The content is low-stakes and a human reviews it before publishing","The AI's draft will be published with no changes","Newsletters legally cannot contain human writing","The AI is guaranteed to know all internal company events"], answer:0, explain:"<strong>The content is low-stakes and a human reviews it before publishing</strong> makes drafting appropriate, since errors are caught by the editor and consequences are minor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI's draft will be published with no changes</b>: publishing unreviewed AI output removes the safeguard that makes this use acceptable.</span><span class='qd'><b>Newsletters legally cannot contain human writing</b>: there is no such rule, and human writing is fully allowed.</span><span class='qd'><b>The AI is guaranteed to know all internal company events</b>: the model will not know private internal events, which is why an editor must add and verify details.</span>" },
{ id:"D2-006", domain:2, obj:"2.1", diff:"medium", q:"An HR manager wants to fully automate final hiring decisions using an AI chatbot with no human involvement. Why is this a poor application of AI?", options:["Chatbots cannot read resumes at all","Hiring decisions carry high stakes and legal/fairness risks that require human accountability","AI is always more biased than any human","It would be too fast to be useful"], answer:1, explain:"<strong>Hiring decisions carry high stakes and legal/fairness risks that require human accountability</strong>, so a fully automated final decision is inappropriate; a person must own the outcome.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Chatbots cannot read resumes at all</b>: they can process resume text; the problem is judgment and accountability, not capability.</span><span class='qd'><b>AI is always more biased than any human</b>: AI can reflect or amplify bias, but the claim that it is always worse is unsupported and not the core issue.</span><span class='qd'><b>It would be too fast to be useful</b>: speed is not the concern; fairness, context, and responsibility are.</span>" },
{ id:"D2-007", domain:2, obj:"2.1", diff:"medium", q:"Which situation is the BEST candidate for using AI to save time?", options:["Signing a legally binding contract on the company's behalf","Deciding which employee to lay off","Reformatting a messy list of notes into a clean bulleted outline","Diagnosing a patient's illness with no doctor involved"], answer:2, explain:"<strong>Reformatting a messy list of notes into a clean bulleted outline</strong> is a low-risk, mechanical text task where AI excels and mistakes are easy to spot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Signing a legally binding contract on the company's behalf</b>: entering binding agreements requires human authority and accountability.</span><span class='qd'><b>Deciding which employee to lay off</b>: this is a high-stakes people decision needing human judgment and fairness review.</span><span class='qd'><b>Diagnosing a patient's illness with no doctor involved</b>: medical diagnosis is high-risk and must involve a qualified professional.</span>" },
{ id:"D2-008", domain:2, obj:"2.1", diff:"medium", q:"A small business owner asks an AI to generate a rough outline for a training session, planning to add their own real examples afterward. What makes this a sound approach?", options:["The owner will present the outline word-for-word without reading it","The AI knows the exact skill level of every employee","Outlines from AI never need any human input","The AI outline is treated as a starting point that the human customizes and verifies"], answer:3, explain:"<strong>The AI outline is treated as a starting point that the human customizes and verifies</strong>, which is the right mindset: AI accelerates the draft while the human supplies real context and checks accuracy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The owner will present the outline word-for-word without reading it</b>: skipping review defeats the safeguard and risks errors or irrelevance.</span><span class='qd'><b>The AI knows the exact skill level of every employee</b>: the model has no knowledge of specific staff, so the owner must adapt it.</span><span class='qd'><b>Outlines from AI never need any human input</b>: AI drafts routinely need human refinement to be accurate and relevant.</span>" },
{ id:"D2-009", domain:2, obj:"2.1", diff:"hard", q:"A logistics analyst must produce a report where every number will be quoted to the board and audited. They consider using a chatbot to invent the figures. What is the MOST appropriate stance?", options:["Use AI to help structure and word the report, but source all figures from verified data systems","Use the chatbot to fabricate plausible numbers to save time","Never use AI for anything in the report","Trust any number the chatbot provides because it sounds confident"], answer:0, explain:"<strong>Use AI to help structure and word the report, but source all figures from verified data systems</strong> correctly separates safe tasks (writing, structure) from unsafe ones (inventing audited numbers).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use the chatbot to fabricate plausible numbers to save time</b>: fabricating figures for an audited report is dishonest and dangerous.</span><span class='qd'><b>Never use AI for anything in the report</b>: AI can still safely help with wording and structure, so a total ban is unnecessary.</span><span class='qd'><b>Trust any number the chatbot provides because it sounds confident</b>: confidence is not accuracy; models can state wrong figures convincingly.</span>" },
{ id:"D2-010", domain:2, obj:"2.1", diff:"hard", q:"Why might using an AI chatbot to answer very recent breaking-news questions be unreliable, even for a capable model?", options:["The model is intentionally programmed to lie about news","The model's knowledge may have a cutoff date and lack the latest events unless it can browse live sources","News questions always trigger a refusal","The model deletes news from its memory hourly"], answer:1, explain:"<strong>The model's knowledge may have a cutoff date and lack the latest events unless it can browse live sources</strong>, so it can miss or misstate very recent developments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model is intentionally programmed to lie about news</b>: the issue is missing recent data, not deliberate lying.</span><span class='qd'><b>News questions always trigger a refusal</b>: models often attempt news answers, which is why stale data is risky.</span><span class='qd'><b>The model deletes news from its memory hourly</b>: models do not continuously delete knowledge; they have a fixed training cutoff.</span>" },
{ id:"D2-011", domain:2, obj:"2.1", diff:"easy", q:"A user wants help rewriting a wordy paragraph to be more concise. Why is this a strong use of AI?", options:["The AI is certain to know the paragraph's hidden legal meaning","It removes the user's responsibility for the final text","It is a language task where the user can easily judge the result","Concise writing is impossible for humans"], answer:2, explain:"<strong>It is a language task where the user can easily judge the result</strong>, making concise rewriting a great fit because the human can quickly confirm the shorter version keeps the meaning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI is certain to know the paragraph's hidden legal meaning</b>: the model may miss nuanced legal implications, so the user must check.</span><span class='qd'><b>It removes the user's responsibility for the final text</b>: the user still owns and must approve the final wording.</span><span class='qd'><b>Concise writing is impossible for humans</b>: humans can write concisely; AI simply speeds it up.</span>" },
{ id:"D2-012", domain:2, obj:"2.1", diff:"medium", q:"When is it MOST appropriate to keep a human closely in the loop while using AI?", options:["When choosing a font color for a slide","When generating a list of icebreaker questions","When suggesting a title for a blog post","When the output will directly affect someone's health, finances, or legal standing"], answer:3, explain:"<strong>When the output will directly affect someone's health, finances, or legal standing</strong> is exactly when human oversight matters most, because the stakes and potential harm are high.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>When choosing a font color for a slide</b>: this is trivial and low-risk, needing little oversight.</span><span class='qd'><b>When generating a list of icebreaker questions</b>: low-stakes creative output is easy to accept or discard.</span><span class='qd'><b>When suggesting a title for a blog post</b>: a title suggestion is minor and easily reviewed.</span>" },
{ id:"D2-013", domain:2, obj:"2.1", diff:"medium", q:"A nonprofit wants AI to draft social-media captions but is unsure about accuracy of any statistics it might include. What is the best practice?", options:["Use the AI for the caption wording but verify any statistic against a trusted source before posting","Publish whatever numbers the AI includes to save time","Let the AI decide which statistics are true","Avoid captions entirely"], answer:0, explain:"<strong>Use the AI for the caption wording but verify any statistic against a trusted source before posting</strong> keeps the creative benefit while guarding against fabricated or wrong figures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish whatever numbers the AI includes to save time</b>: unverified AI statistics can be wrong and damage credibility.</span><span class='qd'><b>Let the AI decide which statistics are true</b>: a model cannot reliably verify truth; that is a human responsibility.</span><span class='qd'><b>Avoid captions entirely</b>: captions are useful; only the numbers need verification.</span>" },
{ id:"D2-014", domain:2, obj:"2.1", diff:"hard", q:"An engineer considers using a chatbot to compute the load-bearing safety limit for a bridge design with no other checks. Why is this inappropriate?", options:["Chatbots cannot output any numbers","Safety-critical calculations demand validated engineering tools and expert review, not an unverified chatbot","The answer would take too long to generate","Bridges do not involve any math"], answer:1, explain:"<strong>Safety-critical calculations demand validated engineering tools and expert review, not an unverified chatbot</strong>, because an error could cause catastrophic harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Chatbots cannot output any numbers</b>: they can output numbers, but those numbers may be wrong, which is the danger.</span><span class='qd'><b>The answer would take too long to generate</b>: speed is irrelevant; correctness and accountability are the concern.</span><span class='qd'><b>Bridges do not involve any math</b>: bridge design is heavily mathematical, underscoring the need for validated tools.</span>" },
{ id:"D2-015", domain:2, obj:"2.1", diff:"medium", q:"Which of these is a hallmark of a task WELL-SUITED to AI assistance?", options:["The consequences of a wrong output are severe and irreversible","The task must be kept secret from every human reviewer","A human can quickly review and correct the output, and errors are low-cost","No source of truth exists to check the answer"], answer:2, explain:"<strong>A human can quickly review and correct the output, and errors are low-cost</strong> describes an ideal AI task: fast human verification plus low downside.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The consequences of a wrong output are severe and irreversible</b>: high, irreversible stakes are a reason for caution, not a good fit.</span><span class='qd'><b>The task must be kept secret from every human reviewer</b>: removing review increases risk rather than suitability.</span><span class='qd'><b>No source of truth exists to check the answer</b>: without any way to verify, reliance on AI is riskier.</span>" },
{ id:"D2-016", domain:2, obj:"2.1", diff:"easy", q:"A user asks AI to translate a casual email into another language for a personal message. Why is this generally acceptable?", options:["AI translations are always perfect and never need review","The message is legally binding once translated","Only AI can translate languages","Machine translation for informal messages is low-stakes and easy to sanity-check"], answer:3, explain:"<strong>Machine translation for informal messages is low-stakes and easy to sanity-check</strong>, so casual translation is a reasonable everyday use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI translations are always perfect and never need review</b>: translations can contain subtle errors, so review is still wise, especially for important messages.</span><span class='qd'><b>The message is legally binding once translated</b>: a casual personal note is not binding, and legal translations would need a professional.</span><span class='qd'><b>Only AI can translate languages</b>: humans and other tools translate too; AI is simply convenient.</span>" },
{ id:"D2-017", domain:2, obj:"2.1", diff:"hard", q:"A compliance officer must interpret a specific clause of a new regulation that will guide a company-wide policy. What is the MOST appropriate use of a chatbot here?", options:["Use the chatbot to get a plain-language explanation, then confirm with the actual regulation and legal counsel","Adopt the chatbot's interpretation as the official legal position immediately","Ignore the regulation because AI can handle compliance","Ask the chatbot to rewrite the regulation to be more favorable"], answer:0, explain:"<strong>Use the chatbot to get a plain-language explanation, then confirm with the actual regulation and legal counsel</strong> uses AI to aid understanding while keeping authoritative interpretation with experts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Adopt the chatbot's interpretation as the official legal position immediately</b>: AI can misread legal nuance, so its answer cannot be the official position.</span><span class='qd'><b>Ignore the regulation because AI can handle compliance</b>: compliance is a serious human and legal responsibility that AI cannot own.</span><span class='qd'><b>Ask the chatbot to rewrite the regulation to be more favorable</b>: you cannot rewrite a regulation to suit yourself; that misunderstands its authority.</span>" },
{ id:"D2-018", domain:2, obj:"2.1", diff:"medium", q:"Which is the strongest reason to prefer a specialized tool over a general chatbot for a spreadsheet full of financial calculations?", options:["General chatbots are illegal for finance","Purpose-built tools compute figures deterministically and are auditable, while a chatbot may approximate or err","Chatbots refuse to open spreadsheets","Spreadsheets cannot hold numbers"], answer:1, explain:"<strong>Purpose-built tools compute figures deterministically and are auditable, while a chatbot may approximate or err</strong> is why exact, repeatable math belongs in the right tool.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>General chatbots are illegal for finance</b>: they are not illegal; they are simply less reliable for exact calculation.</span><span class='qd'><b>Chatbots refuse to open spreadsheets</b>: many can process spreadsheet data; the issue is calculation reliability.</span><span class='qd'><b>Spreadsheets cannot hold numbers</b>: spreadsheets are built for numbers, which is why a deterministic tool fits.</span>" },
{ id:"D2-019", domain:2, obj:"2.1", diff:"easy", q:"A user wants AI to suggest a few polite ways to decline a meeting invitation. Why is this appropriate?", options:["The AI will send the reply automatically without consent","Declining meetings is legally regulated by AI","It is a routine, low-risk writing task the user can easily evaluate","Only AI knows how to be polite"], answer:2, explain:"<strong>It is a routine, low-risk writing task the user can easily evaluate</strong>, making phrasing help for a polite decline a fitting everyday use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI will send the reply automatically without consent</b>: the tool suggests wording; the user still chooses to send.</span><span class='qd'><b>Declining meetings is legally regulated by AI</b>: there is no such regulation; this is ordinary etiquette.</span><span class='qd'><b>Only AI knows how to be polite</b>: humans write polite messages routinely; AI just offers options.</span>" },
{ id:"D2-020", domain:2, obj:"2.1", diff:"medium", q:"An employee wants to paste an entire confidential client contract into a public chatbot to get a summary. Setting privacy aside, why might the SUMMARY itself still be risky to rely on?", options:["Summaries are always word-for-word copies","The contract becomes void once summarized","Chatbots cannot read contracts at all","The model may miss or misstate a critical clause, so the summary needs human verification"], answer:3, explain:"<strong>The model may miss or misstate a critical clause, so the summary needs human verification</strong>, because important legal details can be dropped or distorted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Summaries are always word-for-word copies</b>: a summary condenses and may omit key points, not copy verbatim.</span><span class='qd'><b>The contract becomes void once summarized</b>: summarizing has no effect on a contract's validity.</span><span class='qd'><b>Chatbots cannot read contracts at all</b>: they can process the text; the risk is accuracy of the summary.</span>" },
{ id:"D2-021", domain:2, obj:"2.1", diff:"hard", q:"A team is choosing between AI-assisting a task versus fully automating it. Which combination BEST indicates full automation could be acceptable?", options:["Low stakes, easily verifiable output, and reversible consequences","High stakes, no way to verify, and irreversible outcomes","Unknown stakes and no human available","Life-safety impact with no expert oversight"], answer:0, explain:"<strong>Low stakes, easily verifiable output, and reversible consequences</strong> is the safest profile for greater automation because errors are cheap and correctable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>High stakes, no way to verify, and irreversible outcomes</b>: this is the riskiest profile and argues against automation.</span><span class='qd'><b>Unknown stakes and no human available</b>: uncertainty plus no oversight increases risk, not suitability.</span><span class='qd'><b>Life-safety impact with no expert oversight</b>: safety-critical work without experts is inappropriate to automate.</span>" },
{ id:"D2-022", domain:2, obj:"2.2", diff:"easy", q:"Which AI use would be considered LOW-risk?", options:["Using AI to set an inmate's parole with no human review","Using AI to suggest recipe ideas from ingredients you have","Using AI to approve mortgage applications automatically","Using AI to prescribe medication doses"], answer:1, explain:"<strong>Using AI to suggest recipe ideas from ingredients you have</strong> is low-risk because a wrong suggestion is trivial to ignore and harms no one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Using AI to set an inmate's parole with no human review</b>: parole decisions are high-stakes and affect liberty, requiring human judgment.</span><span class='qd'><b>Using AI to approve mortgage applications automatically</b>: lending decisions carry legal and financial impact and fairness concerns.</span><span class='qd'><b>Using AI to prescribe medication doses</b>: dosing is a medical, safety-critical decision.</span>" },
{ id:"D2-023", domain:2, obj:"2.2", diff:"easy", q:"Which factor MOST increases the risk level of an AI use case?", options:["The task is generating funny captions for friends","The output is easy to undo","The output is used to make consequential decisions about people's lives","The user reads and checks each result"], answer:2, explain:"<strong>The output is used to make consequential decisions about people's lives</strong> raises risk sharply because errors can cause real, lasting harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The task is generating funny captions for friends</b>: this is playful and low-impact.</span><span class='qd'><b>The output is easy to undo</b>: reversibility lowers risk, not raises it.</span><span class='qd'><b>The user reads and checks each result</b>: human verification reduces risk.</span>" },
{ id:"D2-024", domain:2, obj:"2.2", diff:"medium", q:"A hospital wants to use AI to draft the friendly wording of appointment-reminder texts, with staff reviewing them. How should this use be classified?", options:["High-risk, because it involves a hospital","Prohibited, because AI cannot write text","No-risk, because nothing could ever go wrong","Low-risk, because the content is non-clinical and human-reviewed before sending"], answer:3, explain:"<strong>Low-risk, because the content is non-clinical and human-reviewed before sending</strong> correctly weighs the actual task: reminder wording, not medical advice, with human review.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>High-risk, because it involves a hospital</b>: risk depends on the task, not merely the setting; reminder text is benign.</span><span class='qd'><b>Prohibited, because AI cannot write text</b>: AI writes text well; this is a fitting use.</span><span class='qd'><b>No-risk, because nothing could ever go wrong</b>: no use is truly zero-risk, so this overstates safety.</span>" },
{ id:"D2-025", domain:2, obj:"2.2", diff:"medium", q:"Why does the same AI tool (a chatbot) fall into different risk tiers depending on the task?", options:["Risk depends on how the output is used and who it affects, not the tool itself","The tool changes its code for each task","All chatbot uses are automatically high-risk","Risk is decided only by the tool's brand name"], answer:0, explain:"<strong>Risk depends on how the output is used and who it affects, not the tool itself</strong>, so the same model can be low-risk for jokes and high-risk for medical decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tool changes its code for each task</b>: the model does not rewrite itself; the context determines risk.</span><span class='qd'><b>All chatbot uses are automatically high-risk</b>: many uses are clearly low-risk, so a blanket label is wrong.</span><span class='qd'><b>Risk is decided only by the tool's brand name</b>: brand does not set risk; the use case does.</span>" },
{ id:"D2-026", domain:2, obj:"2.2", diff:"hard", q:"An insurance company plans to let an AI model automatically deny or approve claims that determine payouts, with only spot-check audits. What is the BEST characterization?", options:["Low-risk, since audits catch everything","High-risk, because automated decisions materially affect people's finances and may embed bias","No-risk, because insurance is routine","High-risk only if the AI is slow"], answer:1, explain:"<strong>High-risk, because automated decisions materially affect people's finances and may embed bias</strong> reflects the serious impact and fairness exposure of automated payout decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Low-risk, since audits catch everything</b>: spot-checks miss many errors, so they do not make it low-risk.</span><span class='qd'><b>No-risk, because insurance is routine</b>: routine volume does not remove the impact on individuals.</span><span class='qd'><b>High-risk only if the AI is slow</b>: speed is irrelevant to the financial and fairness risk.</span>" },
{ id:"D2-027", domain:2, obj:"2.2", diff:"medium", q:"A user uses AI to help plan a personal weekend trip itinerary. Which best describes the risk and appropriate safeguard?", options:["High-risk; require legal sign-off","Prohibited; itineraries must be handwritten","Low-risk; simply double-check opening hours and bookings before relying on them","No safeguard needed because AI is always right about travel"], answer:2, explain:"<strong>Low-risk; simply double-check opening hours and bookings before relying on them</strong> matches a casual planning task where a quick verification handles the main risk of outdated details.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>High-risk; require legal sign-off</b>: a personal trip plan does not warrant legal review.</span><span class='qd'><b>Prohibited; itineraries must be handwritten</b>: there is no such requirement.</span><span class='qd'><b>No safeguard needed because AI is always right about travel</b>: travel details can be stale or wrong, so a quick check is wise.</span>" },
{ id:"D2-028", domain:2, obj:"2.2", diff:"hard", q:"A school district considers two AI uses: (A) generating draft quiz questions a teacher edits, and (B) automatically assigning final letter grades with no teacher review. How do their risk levels compare?", options:["Both are equally low-risk","A is higher-risk than B","Both are prohibited","A is lower-risk; B is higher-risk because unreviewed grades directly affect students' futures"], answer:3, explain:"<strong>A is lower-risk; B is higher-risk because unreviewed grades directly affect students' futures</strong> correctly ties risk to impact and the absence of human review in B.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both are equally low-risk</b>: assigning final grades without review is far more consequential than editable drafts.</span><span class='qd'><b>A is higher-risk than B</b>: this reverses reality; the reviewed draft is the safer use.</span><span class='qd'><b>Both are prohibited</b>: drafting quiz questions is a legitimate low-risk use, so a blanket ban is wrong.</span>" },
{ id:"D2-029", domain:2, obj:"2.2", diff:"medium", q:"Which safeguard is MOST appropriate to add as an AI use case moves into higher-risk territory?", options:["Add meaningful human review and clear accountability for the final decision","Remove all human oversight to move faster","Hide the use of AI from everyone","Stop verifying outputs to save time"], answer:0, explain:"<strong>Add meaningful human review and clear accountability for the final decision</strong> is the core safeguard for higher-risk uses so a responsible person owns and checks outcomes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Remove all human oversight to move faster</b>: less oversight increases risk exactly when more is needed.</span><span class='qd'><b>Hide the use of AI from everyone</b>: concealment undermines transparency and accountability.</span><span class='qd'><b>Stop verifying outputs to save time</b>: skipping verification is the opposite of a safeguard.</span>" },
{ id:"D2-030", domain:2, obj:"2.2", diff:"easy", q:"Using AI to suggest a playlist name for a party is best described as:", options:["High-risk and irreversible","Low-risk and reversible","A regulated financial activity","A medical decision"], answer:1, explain:"<strong>Low-risk and reversible</strong> fits a playful, inconsequential task where any bad suggestion is trivially ignored.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>High-risk and irreversible</b>: naming a playlist has no serious or lasting consequences.</span><span class='qd'><b>A regulated financial activity</b>: there is nothing financial or regulated about it.</span><span class='qd'><b>A medical decision</b>: it has no medical dimension.</span>" },
{ id:"D2-031", domain:2, obj:"2.2", diff:"hard", q:"A city plans to use an AI system to help prioritize which neighborhoods receive emergency services. Which consideration MOST justifies treating this as high-risk?", options:["It might use a lot of electricity","The AI vendor has a long name","Errors or bias could delay life-saving help to certain communities","It could generate too many suggestions"], answer:2, explain:"<strong>Errors or bias could delay life-saving help to certain communities</strong> is the decisive high-risk factor: potential for serious harm and inequity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It might use a lot of electricity</b>: energy use is a side concern, not the primary risk to people.</span><span class='qd'><b>The AI vendor has a long name</b>: the vendor's name is irrelevant to risk.</span><span class='qd'><b>It could generate too many suggestions</b>: volume of suggestions is minor compared to life-safety impact.</span>" },
{ id:"D2-032", domain:2, obj:"2.2", diff:"medium", q:"An accountant uses AI to reword the explanatory notes in a client report but computes all tax figures in dedicated software. Why is this risk split sensible?", options:["All accounting tasks are equally risky","AI is banned from touching any financial report","Rewording notes is illegal","Wording is low-risk while exact tax numbers are high-stakes and belong in validated tools"], answer:3, explain:"<strong>Wording is low-risk while exact tax numbers are high-stakes and belong in validated tools</strong> matches each subtask to the right approach based on its risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>All accounting tasks are equally risky</b>: rewording notes and computing tax owed differ greatly in stakes.</span><span class='qd'><b>AI is banned from touching any financial report</b>: AI can safely assist with wording; only exact figures need validated tools.</span><span class='qd'><b>Rewording notes is illegal</b>: rewording explanatory text is perfectly legal.</span>" },
{ id:"D2-033", domain:2, obj:"2.2", diff:"medium", q:"Which pairing of use case and risk level is CORRECT?", options:["Generating small-talk topics — low-risk","Drafting a birthday party invite — high-risk","Auto-deciding child custody — low-risk","Setting insulin doses without a clinician — low-risk"], answer:0, explain:"<strong>Generating small-talk topics — low-risk</strong> is correct because casual conversation prompts carry no meaningful consequences.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Drafting a birthday party invite — high-risk</b>: an invite is trivial and low-risk, not high-risk.</span><span class='qd'><b>Auto-deciding child custody — low-risk</b>: custody decisions are extremely high-stakes.</span><span class='qd'><b>Setting insulin doses without a clinician — low-risk</b>: unsupervised dosing is dangerous and high-risk.</span>" },
{ id:"D2-034", domain:2, obj:"2.2", diff:"hard", q:"A bank wants to use AI to draft customer-friendly explanations of why a loan was denied, while the denial decision itself is made by a governed, auditable process. What is the MOST accurate assessment?", options:["Both drafting and deciding are equally trivial","The drafting assist is lower-risk; the decision remains the high-risk, governed part","Explaining a denial in plain language is the highest-risk element","AI must make the denial decision for consistency"], answer:1, explain:"<strong>The drafting assist is lower-risk; the decision remains the high-risk, governed part</strong> properly separates the consequential decision from the benign explanation wording.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both drafting and deciding are equally trivial</b>: the denial decision is far from trivial and is tightly governed.</span><span class='qd'><b>Explaining a denial in plain language is the highest-risk element</b>: clear explanation is low-risk; the decision is the risky part.</span><span class='qd'><b>AI must make the denial decision for consistency</b>: handing the decision to AI increases risk and undermines governance.</span>" },
{ id:"D2-035", domain:2, obj:"2.2", diff:"easy", q:"Which question BEST helps you gauge an AI use case's risk level?", options:["\"What color is the app's logo?\"","\"How many words did the AI produce?\"","\"Who could be harmed, and how badly, if the output is wrong?\"","\"Does the AI have a friendly name?\""], answer:2, explain:"<strong>\"Who could be harmed, and how badly, if the output is wrong?\"</strong> targets impact and severity, the heart of risk assessment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"What color is the app's logo?\"</b>: appearance has nothing to do with risk.</span><span class='qd'><b>\"How many words did the AI produce?\"</b>: output length does not indicate consequence.</span><span class='qd'><b>\"Does the AI have a friendly name?\"</b>: branding is irrelevant to potential harm.</span>" },
{ id:"D2-036", domain:2, obj:"2.2", diff:"medium", q:"A user relies on AI to summarize their own personal journaling for reflection. Compared to using AI to summarize legal evidence for a trial, the journaling use is:", options:["Higher-risk because journals are private","Equally risky because both are summaries","Prohibited because AI cannot summarize","Lower-risk because errors mainly affect only the user and carry no legal weight"], answer:3, explain:"<strong>Lower-risk because errors mainly affect only the user and carry no legal weight</strong> reflects that consequences of a personal reflection error are minor compared with trial evidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Higher-risk because journals are private</b>: privacy matters, but the impact of an error is far smaller than in a trial.</span><span class='qd'><b>Equally risky because both are summaries</b>: identical task types can differ hugely in stakes.</span><span class='qd'><b>Prohibited because AI cannot summarize</b>: summarizing is a core AI strength.</span>" },
{ id:"D2-037", domain:2, obj:"2.2", diff:"hard", q:"When escalating from a low-risk to a high-risk AI deployment, which change is LEAST appropriate?", options:["Reducing oversight and testing to speed things up","Adding human review of outputs","Documenting who is accountable for decisions","Increasing monitoring for bias and errors"], answer:0, explain:"<strong>Reducing oversight and testing to speed things up</strong> is the wrong move; higher risk calls for more scrutiny, not less.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Adding human review of outputs</b>: this is an appropriate safeguard for higher risk.</span><span class='qd'><b>Documenting who is accountable for decisions</b>: clear accountability is essential as stakes rise.</span><span class='qd'><b>Increasing monitoring for bias and errors</b>: more monitoring is exactly right for higher-risk use.</span>" },
{ id:"D2-038", domain:2, obj:"2.2", diff:"easy", q:"Auto-generating alt text suggestions for images that an editor reviews before publishing is best classified as:", options:["High-risk requiring legal counsel","Low-risk with light human review","A safety-critical medical task","Prohibited under all circumstances"], answer:1, explain:"<strong>Low-risk with light human review</strong> fits a helpful accessibility assist where a quick human check catches any mistakes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>High-risk requiring legal counsel</b>: alt text suggestions do not warrant legal review.</span><span class='qd'><b>A safety-critical medical task</b>: it has no medical or safety dimension.</span><span class='qd'><b>Prohibited under all circumstances</b>: it is a beneficial, common use.</span>" },
{ id:"D2-039", domain:2, obj:"2.2", diff:"medium", q:"A recruiter uses AI to screen and auto-reject candidates before any human sees the applications. Which risk is MOST elevated by removing the human screen?", options:["The electricity cost of screening","The AI might work too quickly","Qualified applicants may be unfairly filtered out with no one to catch the error","Resumes could be too long to read"], answer:2, explain:"<strong>Qualified applicants may be unfairly filtered out with no one to catch the error</strong> is the key elevated risk when humans are removed from a consequential gate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The electricity cost of screening</b>: energy is a trivial concern next to fairness.</span><span class='qd'><b>The AI might work too quickly</b>: speed is not the harm; wrongful exclusion is.</span><span class='qd'><b>Resumes could be too long to read</b>: length is unrelated to the fairness risk introduced.</span>" },
{ id:"D2-040", domain:2, obj:"2.2", diff:"hard", q:"Two teams use AI on customer data. Team A generates internal draft FAQs; Team B auto-sends AI-written medical guidance to patients. Which statement is MOST accurate?", options:["Both are low-risk internal tasks","Team A is higher-risk because FAQs are public","Neither carries any risk","Team B is higher-risk because unreviewed medical guidance to patients can cause real harm"], answer:3, explain:"<strong>Team B is higher-risk because unreviewed medical guidance to patients can cause real harm</strong> correctly identifies the safety-critical, unreviewed output as the greater danger.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both are low-risk internal tasks</b>: Team B's output is external medical guidance, not a low-risk internal draft.</span><span class='qd'><b>Team A is higher-risk because FAQs are public</b>: reviewed internal drafts are far less risky than unreviewed medical advice.</span><span class='qd'><b>Neither carries any risk</b>: medical guidance to patients clearly carries risk.</span>" },
{ id:"D2-041", domain:2, obj:"2.3", diff:"easy", q:"When an AI chatbot states a confident but false fact, such as a fake court case or invented citation, this is commonly called a(n):", options:["Hallucination","Encryption","Firewall","Backup"], answer:0, explain:"<strong>Hallucination</strong> is the term for an AI confidently producing information that is false or fabricated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption</b>: encryption protects data confidentiality and is unrelated to false outputs.</span><span class='qd'><b>Firewall</b>: a firewall filters network traffic and has nothing to do with AI accuracy.</span><span class='qd'><b>Backup</b>: a backup is a stored copy of data, not an AI error.</span>" },
{ id:"D2-042", domain:2, obj:"2.3", diff:"easy", q:"AI bias most often originates from:", options:["The color scheme of the user interface","AI bias most often comes from patterns and imbalances in the data the model learned from","The user typing too quickly","The time of day the model is used"], answer:1, explain:"<strong>AI bias most often comes from patterns and imbalances in the data the model learned from</strong>, since models reflect what is in their training data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The color scheme of the user interface</b>: appearance does not affect model bias.</span><span class='qd'><b>The user typing too quickly</b>: input speed has no bearing on bias.</span><span class='qd'><b>The time of day the model is used</b>: timing does not influence learned bias.</span>" },
{ id:"D2-043", domain:2, obj:"2.3", diff:"medium", q:"A user asks a chatbot for sources on a topic, and it lists three books that do not exist. What is the BEST response?", options:["Trust the list because the titles look real","Assume all three are correct and publish immediately","Verify each source independently before citing, since the model may have fabricated them","Ask the chatbot to promise the books are real"], answer:2, explain:"<strong>Verify each source independently before citing, since the model may have fabricated them</strong> is correct because hallucinated citations are common and only external checking confirms them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the list because the titles look real</b>: plausible-looking titles are exactly how hallucinations deceive.</span><span class='qd'><b>Assume all three are correct and publish immediately</b>: publishing unverified sources spreads misinformation.</span><span class='qd'><b>Ask the chatbot to promise the books are real</b>: a model's reassurance is not evidence of accuracy.</span>" },
{ id:"D2-044", domain:2, obj:"2.3", diff:"medium", q:"Why is pasting a customer's full name, address, and account number into a public AI chatbot a privacy concern?", options:["The chatbot will refuse to read names","Account numbers make the AI faster","Names cannot be typed into chatbots","Personal data may be stored or exposed outside your control and could breach privacy rules"], answer:3, explain:"<strong>Personal data may be stored or exposed outside your control and could breach privacy rules</strong> captures the risk of sharing identifiable information with an external service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The chatbot will refuse to read names</b>: chatbots readily process names, which is why the exposure is real.</span><span class='qd'><b>Account numbers make the AI faster</b>: sensitive data does not affect speed and is irrelevant to the concern.</span><span class='qd'><b>Names cannot be typed into chatbots</b>: names can be typed, which is precisely the problem.</span>" },
{ id:"D2-045", domain:2, obj:"2.3", diff:"medium", q:"A designer uses an AI image generator and wants to publish the result commercially. Which risk should they consider regarding intellectual property?", options:["The output might resemble copyrighted work or have unclear usage rights","AI images are always in the public domain by law","Publishing any AI image is a criminal offense","AI images cannot be saved as files"], answer:0, explain:"<strong>The output might resemble copyrighted work or have unclear usage rights</strong> is the key IP concern, since generated content can echo protected material or come with uncertain licensing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI images are always in the public domain by law</b>: rights vary by tool and jurisdiction; this blanket claim is false.</span><span class='qd'><b>Publishing any AI image is a criminal offense</b>: publishing AI images is not inherently criminal.</span><span class='qd'><b>AI images cannot be saved as files</b>: they can be saved; that is unrelated to IP risk.</span>" },
{ id:"D2-046", domain:2, obj:"2.3", diff:"hard", q:"A resume-screening AI was trained mostly on resumes of past hires from one demographic. What is the MOST likely fairness risk?", options:["It will run out of storage","It may favor candidates resembling past hires and disadvantage others","It will translate resumes incorrectly","It will make resumes load slowly"], answer:1, explain:"<strong>It may favor candidates resembling past hires and disadvantage others</strong> is the classic bias outcome when training data reflects a non-representative history.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It will run out of storage</b>: storage is unrelated to fairness in screening.</span><span class='qd'><b>It will translate resumes incorrectly</b>: translation errors are not the bias risk described.</span><span class='qd'><b>It will make resumes load slowly</b>: load time has nothing to do with biased selection.</span>" },
{ id:"D2-047", domain:2, obj:"2.3", diff:"easy", q:"Which practice best reduces the harm from AI hallucinations in your work?", options:["Assume the AI is never wrong","Only ask the AI questions with no correct answer","Fact-check important claims against reliable sources before relying on them","Turn off your monitor while it answers"], answer:2, explain:"<strong>Fact-check important claims against reliable sources before relying on them</strong> is the essential habit that catches fabricated or wrong AI statements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the AI is never wrong</b>: overtrust is exactly what makes hallucinations harmful.</span><span class='qd'><b>Only ask the AI questions with no correct answer</b>: this avoids usefulness and does not address factual tasks.</span><span class='qd'><b>Turn off your monitor while it answers</b>: this does nothing to verify accuracy.</span>" },
{ id:"D2-048", domain:2, obj:"2.3", diff:"medium", q:"A chatbot summarizes a news article and adds a statistic that was not in the original. This is an example of:", options:["A perfect summary","An encryption error","A hardware failure","A hallucinated detail the model invented"], answer:3, explain:"<strong>A hallucinated detail the model invented</strong> describes an AI adding information not present in the source, a common accuracy risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A perfect summary</b>: a summary that introduces false facts is the opposite of perfect.</span><span class='qd'><b>An encryption error</b>: encryption is unrelated to fabricated content.</span><span class='qd'><b>A hardware failure</b>: this is a model behavior, not a hardware problem.</span>" },
{ id:"D2-049", domain:2, obj:"2.3", diff:"hard", q:"An employee wants to share proprietary source code with a public AI to get help. Which intellectual-property risk is MOST relevant?", options:["The code could be exposed or retained, risking loss of trade-secret protection","The code will run faster after being pasted","The AI will copyright the code for the employee","Sharing code deletes it locally"], answer:0, explain:"<strong>The code could be exposed or retained, risking loss of trade-secret protection</strong> is the central IP concern when confidential code leaves the organization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The code will run faster after being pasted</b>: pasting code into a chatbot does not change its performance.</span><span class='qd'><b>The AI will copyright the code for the employee</b>: chatbots do not register copyrights, and sharing may weaken protections.</span><span class='qd'><b>Sharing code deletes it locally</b>: sharing does not remove the local copy.</span>" },
{ id:"D2-050", domain:2, obj:"2.3", diff:"medium", q:"Which statement about AI bias is MOST accurate?", options:["Bias only occurs if a programmer is malicious","Bias can lead to unfair outcomes even when no one intended to discriminate","Bias disappears if the model is large enough","Bias only affects images, not text"], answer:1, explain:"<strong>Bias can lead to unfair outcomes even when no one intended to discriminate</strong> because bias often stems from data patterns, not intent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bias only occurs if a programmer is malicious</b>: most bias is unintentional, arising from data.</span><span class='qd'><b>Bias disappears if the model is large enough</b>: larger models can still reflect and amplify bias.</span><span class='qd'><b>Bias only affects images, not text</b>: bias appears in text outputs too.</span>" },
{ id:"D2-051", domain:2, obj:"2.3", diff:"easy", q:"Before trusting an AI's answer to a factual question that matters, you should:", options:["Ask the AI to rate its own honesty","Assume confident phrasing means it is correct","Verify it against an authoritative source","Share it widely first, then check later"], answer:2, explain:"<strong>Verify it against an authoritative source</strong> is the reliable way to confirm important facts an AI provides.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the AI to rate its own honesty</b>: a self-rating is not independent verification.</span><span class='qd'><b>Assume confident phrasing means it is correct</b>: confidence does not equal accuracy in AI outputs.</span><span class='qd'><b>Share it widely first, then check later</b>: spreading unverified claims risks misinformation.</span>" },
{ id:"D2-052", domain:2, obj:"2.3", diff:"hard", q:"A hospital chatbot trained mainly on data from one population gives less accurate advice for other groups. This is BEST described as:", options:["A network latency issue","An unavoidable law of physics","A user typing mistake","A representational bias caused by non-representative training data"], answer:3, explain:"<strong>A representational bias caused by non-representative training data</strong> explains why performance is worse for underrepresented groups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A network latency issue</b>: latency concerns speed, not accuracy across groups.</span><span class='qd'><b>An unavoidable law of physics</b>: this is a data problem that can be mitigated, not physics.</span><span class='qd'><b>A user typing mistake</b>: the disparity comes from training data, not user input.</span>" },
{ id:"D2-053", domain:2, obj:"2.3", diff:"medium", q:"An author uses AI to help write a novel and plans to sell it. Which IP caution is MOST reasonable?", options:["Check the tool's terms on ownership and ensure the text does not copy protected works","Assume the AI holds the copyright and can sue","Believe selling AI-assisted writing is always illegal","Ignore the tool's terms of service entirely"], answer:0, explain:"<strong>Check the tool's terms on ownership and ensure the text does not copy protected works</strong> is prudent, since usage rights vary and outputs could echo existing material.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the AI holds the copyright and can sue</b>: the tool is not a legal person that sues over the text you generate.</span><span class='qd'><b>Believe selling AI-assisted writing is always illegal</b>: AI-assisted writing can often be sold, subject to terms and originality.</span><span class='qd'><b>Ignore the tool's terms of service entirely</b>: the terms define your rights and must be read.</span>" },
{ id:"D2-054", domain:2, obj:"2.3", diff:"medium", q:"Which situation is the clearest example of a PRIVACY risk from AI use?", options:["Asking AI to suggest a metaphor for a poem","Entering a client's medical history into a public chatbot to draft a letter","Using AI to brainstorm team-building games","Requesting a summary of a public Wikipedia article"], answer:1, explain:"<strong>Entering a client's medical history into a public chatbot to draft a letter</strong> exposes sensitive personal data to an external service, a clear privacy risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking AI to suggest a metaphor for a poem</b>: this involves no personal data.</span><span class='qd'><b>Using AI to brainstorm team-building games</b>: brainstorming activities exposes no private information.</span><span class='qd'><b>Requesting a summary of a public Wikipedia article</b>: public content carries no personal-privacy exposure.</span>" },
{ id:"D2-055", domain:2, obj:"2.3", diff:"hard", q:"A team notices their AI hiring tool rejects applicants from certain zip codes at much higher rates. What is the MOST responsible next step?", options:["Assume the pattern is a coincidence and continue","Delete the complaint and keep using it","Investigate the tool for bias and pause its use for consequential decisions until reviewed","Increase the rejection rate to be consistent"], answer:2, explain:"<strong>Investigate the tool for bias and pause its use for consequential decisions until reviewed</strong> is the responsible action when a possible discriminatory pattern appears.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the pattern is a coincidence and continue</b>: dismissing a clear disparity risks ongoing harm.</span><span class='qd'><b>Delete the complaint and keep using it</b>: suppressing concerns is unethical and worsens exposure.</span><span class='qd'><b>Increase the rejection rate to be consistent</b>: this compounds the unfairness rather than fixing it.</span>" },
{ id:"D2-056", domain:2, obj:"2.3", diff:"easy", q:"Which is a realistic limitation to keep in mind about AI-generated text?", options:["It is always 100% accurate","It can never make grammatical errors","It always cites real sources","It can sound authoritative while being factually wrong"], answer:3, explain:"<strong>It can sound authoritative while being factually wrong</strong> is a core limitation that makes verification necessary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is always 100% accurate</b>: AI is not always accurate and can hallucinate.</span><span class='qd'><b>It can never make grammatical errors</b>: AI can and does make errors.</span><span class='qd'><b>It always cites real sources</b>: AI may invent citations, so sources must be checked.</span>" },
{ id:"D2-057", domain:2, obj:"2.3", diff:"medium", q:"An employee pastes an unreleased product roadmap into a free public AI tool. Beyond privacy, what BROADER organizational risk arises?", options:["Loss of confidential competitive information if the data is retained or exposed","The roadmap will format itself automatically","The tool will patent the roadmap for the company","The roadmap becomes easier to print"], answer:0, explain:"<strong>Loss of confidential competitive information if the data is retained or exposed</strong> is the broader business risk of leaking strategic secrets to an outside service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The roadmap will format itself automatically</b>: formatting is trivial and not the risk.</span><span class='qd'><b>The tool will patent the roadmap for the company</b>: tools do not file patents on your behalf, and sharing can harm protection.</span><span class='qd'><b>The roadmap becomes easier to print</b>: printability is irrelevant to the confidentiality risk.</span>" },
{ id:"D2-058", domain:2, obj:"2.3", diff:"hard", q:"Which combination BEST reduces both hallucination and privacy risk when using a public chatbot for work?", options:["Trust all outputs and paste any data freely","Verify factual outputs against trusted sources and avoid entering sensitive personal or confidential data","Only use the chatbot late at night","Turn off spell-check and share more data"], answer:1, explain:"<strong>Verify factual outputs against trusted sources and avoid entering sensitive personal or confidential data</strong> addresses accuracy and privacy together, the two main risks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust all outputs and paste any data freely</b>: this maximizes both risks instead of reducing them.</span><span class='qd'><b>Only use the chatbot late at night</b>: timing does not affect accuracy or data exposure.</span><span class='qd'><b>Turn off spell-check and share more data</b>: this does nothing helpful and increases data exposure.</span>" },
{ id:"D2-059", domain:2, obj:"2.3", diff:"medium", q:"A marketer asks AI to write copy that quotes a famous song's lyrics extensively in an ad. Which risk is MOST relevant?", options:["The ad will load too slowly","The AI will delete the lyrics","Copyright infringement from using protected lyrics without permission","Songs cannot be quoted at all"], answer:2, explain:"<strong>Copyright infringement from using protected lyrics without permission</strong> is the key IP risk when reproducing substantial protected content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The ad will load too slowly</b>: load time is unrelated to copyright.</span><span class='qd'><b>The AI will delete the lyrics</b>: deletion is not the concern; unauthorized use is.</span><span class='qd'><b>Songs cannot be quoted at all</b>: limited quotation may be allowed, but extensive use without permission risks infringement.</span>" },
{ id:"D2-060", domain:2, obj:"2.3", diff:"hard", q:"Which scenario shows hallucination causing REAL harm rather than mere inconvenience?", options:["A user gets a slightly awkward synonym suggestion","A poem's rhythm is a little off","A brainstorm list has one repeated idea","A lawyer files a brief citing AI-invented cases that do not exist"], answer:3, explain:"<strong>A lawyer files a brief citing AI-invented cases that do not exist</strong> shows serious consequences: sanctions, harm to a client, and damaged credibility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A user gets a slightly awkward synonym suggestion</b>: this is a trivial, easily ignored issue.</span><span class='qd'><b>A poem's rhythm is a little off</b>: a minor stylistic flaw causes no real harm.</span><span class='qd'><b>A brainstorm list has one repeated idea</b>: a duplicate idea is a negligible inconvenience.</span>" },
{ id:"D2-061", domain:2, obj:"2.4", diff:"easy", q:"Why is transparency about using AI important when publishing content that could influence people?", options:["It lets the audience judge the source and helps maintain trust","It makes the AI run faster","It is required to charge more money","It hides mistakes from the audience"], answer:0, explain:"<strong>It lets the audience judge the source and helps maintain trust</strong> is why disclosure matters: people deserve to know how content was produced.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the AI run faster</b>: disclosure has no effect on performance.</span><span class='qd'><b>It is required to charge more money</b>: transparency is about honesty, not pricing.</span><span class='qd'><b>It hides mistakes from the audience</b>: transparency reveals context rather than concealing errors.</span>" },
{ id:"D2-062", domain:2, obj:"2.4", diff:"easy", q:"An AI tool used for loan approvals is found to disadvantage a protected group. Which ethical concern is MOST directly raised?", options:["The tool's download size","Fairness and potential discrimination against that group","The color of the approval letter","The speed of the internet connection"], answer:1, explain:"<strong>Fairness and potential discrimination against that group</strong> is the central ethical issue when an AI systematically disadvantages people based on a protected characteristic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tool's download size</b>: technical size is irrelevant to the ethical harm.</span><span class='qd'><b>The color of the approval letter</b>: presentation has nothing to do with fairness.</span><span class='qd'><b>The speed of the internet connection</b>: connectivity does not relate to discrimination.</span>" },
{ id:"D2-063", domain:2, obj:"2.4", diff:"medium", q:"A company deploys AI that automates many routine jobs. Which SOCIETAL impact deserves ethical consideration?", options:["Whether the AI likes its job","The font used in the AI's reports","The effect on displaced workers and the need for retraining or support","The number of servers in the data center"], answer:2, explain:"<strong>The effect on displaced workers and the need for retraining or support</strong> is a genuine societal and ethical concern of workforce automation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whether the AI likes its job</b>: AI has no feelings or job satisfaction to consider.</span><span class='qd'><b>The font used in the AI's reports</b>: typography is unrelated to societal impact.</span><span class='qd'><b>The number of servers in the data center</b>: infrastructure count is not the human-impact question here.</span>" },
{ id:"D2-064", domain:2, obj:"2.4", diff:"medium", q:"Why can widespread AI-generated misinformation be an ethical concern for society?", options:["It uses too many keyboard characters","It makes websites load faster","It only affects one person at a time","It can erode public trust and mislead people at scale"], answer:3, explain:"<strong>It can erode public trust and mislead people at scale</strong> because convincing false content spread widely can distort public understanding and decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It uses too many keyboard characters</b>: character count is irrelevant to the harm.</span><span class='qd'><b>It makes websites load faster</b>: performance is unrelated to misinformation harm.</span><span class='qd'><b>It only affects one person at a time</b>: the danger is precisely its large-scale reach.</span>" },
{ id:"D2-065", domain:2, obj:"2.4", diff:"hard", q:"A city deploys AI facial recognition for policing. Which ethical concern is MOST significant for affected communities?", options:["Potential for wrongful identification and disproportionate impact on certain groups","The camera brand's warranty length","The resolution of the video thumbnails","The color of the police uniforms"], answer:0, explain:"<strong>Potential for wrongful identification and disproportionate impact on certain groups</strong> is the core ethical risk, given documented accuracy gaps and civil-liberty concerns.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The camera brand's warranty length</b>: warranty terms do not bear on rights or fairness.</span><span class='qd'><b>The resolution of the video thumbnails</b>: thumbnail quality is not the ethical issue.</span><span class='qd'><b>The color of the police uniforms</b>: uniforms are irrelevant to the harm.</span>" },
{ id:"D2-066", domain:2, obj:"2.4", diff:"medium", q:"An organization uses AI to personalize content so aggressively that users only see views they already agree with. Which societal concern does this raise?", options:["Faster page rendering","Creation of echo chambers that reduce exposure to diverse perspectives","Lower electricity bills","Shorter passwords"], answer:1, explain:"<strong>Creation of echo chambers that reduce exposure to diverse perspectives</strong> is a recognized societal downside of overly narrow personalization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster page rendering</b>: rendering speed is unrelated to the ethical concern.</span><span class='qd'><b>Lower electricity bills</b>: cost savings do not address the harm to discourse.</span><span class='qd'><b>Shorter passwords</b>: password length has nothing to do with echo chambers.</span>" },
{ id:"D2-067", domain:2, obj:"2.4", diff:"easy", q:"Which action best reflects using AI ethically toward individuals?", options:["Hiding all AI use to avoid questions","Collecting as much personal data as possible without asking","Being transparent and getting consent when AI processes people's personal data","Ignoring how outputs affect people"], answer:2, explain:"<strong>Being transparent and getting consent when AI processes people's personal data</strong> respects individual autonomy and rights.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hiding all AI use to avoid questions</b>: concealment undermines trust and accountability.</span><span class='qd'><b>Collecting as much personal data as possible without asking</b>: excessive collection without consent is unethical.</span><span class='qd'><b>Ignoring how outputs affect people</b>: ignoring impact abandons ethical responsibility.</span>" },
{ id:"D2-068", domain:2, obj:"2.4", diff:"hard", q:"A generative AI is used to create deepfake videos of a real person saying things they never said. Which ethical harm is MOST directly implicated?", options:["Slower video download times","Higher printing costs","Reduced screen brightness","Deception and damage to the person's reputation and consent"], answer:3, explain:"<strong>Deception and damage to the person's reputation and consent</strong> is the central ethical harm of non-consensual deepfakes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slower video download times</b>: performance is unrelated to the harm.</span><span class='qd'><b>Higher printing costs</b>: printing has nothing to do with a video deepfake.</span><span class='qd'><b>Reduced screen brightness</b>: display settings are irrelevant to the ethical issue.</span>" },
{ id:"D2-069", domain:2, obj:"2.4", diff:"medium", q:"Which of the following BEST supports accountability when an AI system makes a consequential decision?", options:["Being able to explain the decision and identify a responsible human owner","Refusing to tell anyone how the decision was made","Blaming the software so no person is responsible","Deleting the logs after each decision"], answer:0, explain:"<strong>Being able to explain the decision and identify a responsible human owner</strong> underpins accountability for high-impact AI decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Refusing to tell anyone how the decision was made</b>: opacity destroys accountability.</span><span class='qd'><b>Blaming the software so no person is responsible</b>: shifting blame to a tool evades responsibility.</span><span class='qd'><b>Deleting the logs after each decision</b>: destroying records prevents any review or accountability.</span>" },
{ id:"D2-070", domain:2, obj:"2.4", diff:"medium", q:"A social platform uses AI to recommend content to teenagers. Which ethical consideration is MOST relevant?", options:["The recommendation engine's file name","Potential impact on well-being, such as promoting harmful or addictive content","The number of colors in the app icon","How fast the app updates its logo"], answer:1, explain:"<strong>Potential impact on well-being, such as promoting harmful or addictive content</strong> is a serious ethical concern when recommending content to vulnerable young users.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The recommendation engine's file name</b>: internal naming has no ethical bearing.</span><span class='qd'><b>The number of colors in the app icon</b>: icon design is irrelevant to well-being.</span><span class='qd'><b>How fast the app updates its logo</b>: logo updates do not affect the ethical issue.</span>" },
{ id:"D2-071", domain:2, obj:"2.4", diff:"hard", q:"An AI grant-review system consistently scores proposals from smaller or rural organizations lower. Which ethical principle is MOST at stake?", options:["The speed of the scoring algorithm","The brand of computer used","Equity and fair access to opportunity across communities","The size of the proposal PDF"], answer:2, explain:"<strong>Equity and fair access to opportunity across communities</strong> is the ethical principle threatened when an AI systematically disadvantages certain groups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The speed of the scoring algorithm</b>: speed is unrelated to fairness of outcomes.</span><span class='qd'><b>The brand of computer used</b>: hardware brand has no ethical relevance.</span><span class='qd'><b>The size of the proposal PDF</b>: file size does not concern equity.</span>" },
{ id:"D2-072", domain:2, obj:"2.4", diff:"easy", q:"Which is an example of using AI responsibly with respect to human oversight?", options:["The AI makes all decisions with no way to appeal","Humans are removed to cut costs","The AI's decisions are never explained","A human reviews and can override AI recommendations in high-stakes decisions"], answer:3, explain:"<strong>A human reviews and can override AI recommendations in high-stakes decisions</strong> embodies responsible oversight where people retain meaningful control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI makes all decisions with no way to appeal</b>: removing appeals abandons oversight and fairness.</span><span class='qd'><b>Humans are removed to cut costs</b>: cutting oversight for cost increases risk in high-stakes settings.</span><span class='qd'><b>The AI's decisions are never explained</b>: unexplained decisions undermine accountability.</span>" },
{ id:"D2-073", domain:2, obj:"2.4", diff:"medium", q:"Why is it ethically important to consider WHO is left out of an AI system's training data?", options:["Groups absent from the data may receive worse or unfair treatment from the system","Missing data makes the model file smaller","It changes the model's color scheme","Absent groups make the AI faster"], answer:0, explain:"<strong>Groups absent from the data may receive worse or unfair treatment from the system</strong>, so representation directly affects fairness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Missing data makes the model file smaller</b>: file size is not the ethical point.</span><span class='qd'><b>It changes the model's color scheme</b>: appearance is unrelated to representation.</span><span class='qd'><b>Absent groups make the AI faster</b>: speed is irrelevant to fairness.</span>" },
{ id:"D2-074", domain:2, obj:"2.4", diff:"hard", q:"A company markets an AI chatbot as a licensed therapist without disclosing it is AI. Which ethical problems are MOST directly raised?", options:["The chatbot's response speed","Deception about the nature of the service and potential harm to vulnerable users","The company's office location","The chatbot's font choice"], answer:1, explain:"<strong>Deception about the nature of the service and potential harm to vulnerable users</strong> captures the twin ethical failures of misrepresentation and risk to people seeking help.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The chatbot's response speed</b>: speed is not the ethical failing here.</span><span class='qd'><b>The company's office location</b>: location is irrelevant to the harm.</span><span class='qd'><b>The chatbot's font choice</b>: typography has no bearing on the deception.</span>" },
{ id:"D2-075", domain:2, obj:"2.4", diff:"medium", q:"Which is the BEST reason to include diverse stakeholders when designing an AI system that affects the public?", options:["They make the launch party larger","They reduce the number of servers needed","They help surface potential harms and biases that designers might miss","They guarantee the AI never makes errors"], answer:2, explain:"<strong>They help surface potential harms and biases that designers might miss</strong> is why inclusive input improves fairness and safety.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They make the launch party larger</b>: this is not a serious rationale.</span><span class='qd'><b>They reduce the number of servers needed</b>: stakeholder input does not change infrastructure.</span><span class='qd'><b>They guarantee the AI never makes errors</b>: no process guarantees zero errors.</span>" },
{ id:"D2-076", domain:2, obj:"2.4", diff:"easy", q:"An ethical use of AI in content creation would include:", options:["Passing AI work off as original expert research when it is not","Fabricating quotes from real people","Hiding that data was used without consent","Disclosing AI involvement when it matters to the audience"], answer:3, explain:"<strong>Disclosing AI involvement when it matters to the audience</strong> reflects honesty and respect for the audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Passing AI work off as original expert research when it is not</b>: misrepresentation deceives the audience.</span><span class='qd'><b>Fabricating quotes from real people</b>: inventing quotes is dishonest and harmful.</span><span class='qd'><b>Hiding that data was used without consent</b>: concealing non-consensual data use is unethical.</span>" },
{ id:"D2-077", domain:2, obj:"2.4", diff:"hard", q:"An AI system's benefits accrue mostly to one group while its risks fall on another. Which ethical concept BEST names this imbalance?", options:["Distributive injustice, where benefits and burdens are shared unfairly","Data compression","Network redundancy","Version control"], answer:0, explain:"<strong>Distributive injustice, where benefits and burdens are shared unfairly</strong> names the ethical problem of unequal distribution of gains and harms.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data compression</b>: this is a technical concept unrelated to fairness.</span><span class='qd'><b>Network redundancy</b>: redundancy concerns reliability, not justice.</span><span class='qd'><b>Version control</b>: version control tracks changes to files, not ethical distribution.</span>" },
{ id:"D2-078", domain:2, obj:"2.4", diff:"medium", q:"A manager plans to use AI to monitor employees' every keystroke and message. Which ethical tension is MOST relevant?", options:["Deciding the monitor's screen size","Balancing legitimate oversight against employee privacy and dignity","Choosing the report's background color","Selecting the server's location"], answer:1, explain:"<strong>Balancing legitimate oversight against employee privacy and dignity</strong> is the core ethical tension in pervasive workplace surveillance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deciding the monitor's screen size</b>: hardware choices are not the ethical issue.</span><span class='qd'><b>Choosing the report's background color</b>: presentation is irrelevant to privacy.</span><span class='qd'><b>Selecting the server's location</b>: server location does not capture the dignity concern.</span>" },
{ id:"D2-079", domain:2, obj:"2.4", diff:"hard", q:"A well-intentioned AI tool to flag at-risk students disproportionately flags students from one background, subjecting them to extra scrutiny. What does this illustrate?", options:["Bias only happens with malicious intent","Monitoring outcomes is unnecessary","Good intentions do not prevent biased outcomes, so impact must be measured and corrected","Intentions alone guarantee fairness"], answer:2, explain:"<strong>Good intentions do not prevent biased outcomes, so impact must be measured and corrected</strong> is the key lesson: fairness depends on real-world results, not intent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bias only happens with malicious intent</b>: this case shows bias arising despite good intent.</span><span class='qd'><b>Monitoring outcomes is unnecessary</b>: monitoring is exactly what reveals the disparate impact.</span><span class='qd'><b>Intentions alone guarantee fairness</b>: intentions do not guarantee fair outcomes.</span>" },
{ id:"D2-080", domain:2, obj:"2.4", diff:"medium", q:"Which statement reflects a mature, ethical view of AI's societal role?", options:["AI should be adopted everywhere with no limits","AI has no impact on society","Ethics only matter for the AI's developers, not users","AI can bring benefits but requires oversight to manage risks to people and communities"], answer:3, explain:"<strong>AI can bring benefits but requires oversight to manage risks to people and communities</strong> is a balanced, responsible stance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI should be adopted everywhere with no limits</b>: unlimited adoption ignores real risks.</span><span class='qd'><b>AI has no impact on society</b>: AI clearly affects society in many ways.</span><span class='qd'><b>Ethics only matter for the AI's developers, not users</b>: users share responsibility for ethical use.</span>" },
{ id:"D2-081", domain:2, obj:"2.5", diff:"easy", q:"Which is the SAFEST practice when you must use AI to help with a document containing customer names and details?", options:["Remove or anonymize the personal data before submitting it to the tool","Paste everything as-is into a public chatbot","Add extra personal details for context","Share the data on social media first"], answer:0, explain:"<strong>Remove or anonymize the personal data before submitting it to the tool</strong> protects individuals while still letting you use AI for the task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste everything as-is into a public chatbot</b>: this exposes sensitive data unnecessarily.</span><span class='qd'><b>Add extra personal details for context</b>: adding more personal data increases exposure.</span><span class='qd'><b>Share the data on social media first</b>: publicly posting personal data is a serious breach.</span>" },
{ id:"D2-082", domain:2, obj:"2.5", diff:"easy", q:"When should you disclose that content was created with AI assistance?", options:["Never, under any circumstances","When the audience's trust or decisions could be affected by knowing the source","Only if the AI asks you to","Only when the content is fictional"], answer:1, explain:"<strong>When the audience's trust or decisions could be affected by knowing the source</strong> is the guiding rule for AI disclosure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never, under any circumstances</b>: hiding AI use can mislead audiences who deserve to know.</span><span class='qd'><b>Only if the AI asks you to</b>: the tool does not decide disclosure; the impact on people does.</span><span class='qd'><b>Only when the content is fictional</b>: disclosure often matters most for factual or influential content.</span>" },
{ id:"D2-083", domain:2, obj:"2.5", diff:"medium", q:"An employee wants to summarize an internal document marked confidential using a free public AI tool. What is the BEST first step?", options:["Paste it into any tool immediately","Email it to a personal account first","Check company policy and use an approved tool or one with proper data protections","Post it in a public forum for help"], answer:2, explain:"<strong>Check company policy and use an approved tool or one with proper data protections</strong> is the responsible first step before handling confidential data with AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste it into any tool immediately</b>: skipping policy checks risks a data leak.</span><span class='qd'><b>Email it to a personal account first</b>: moving confidential data to personal email creates more exposure.</span><span class='qd'><b>Post it in a public forum for help</b>: publicizing confidential content is a clear breach.</span>" },
{ id:"D2-084", domain:2, obj:"2.5", diff:"medium", q:"Why should you review the privacy settings or data policy of an AI tool before entering work data?", options:["Reading policies makes the tool respond faster","Policies change the AI's writing style","It is required to unlock premium fonts","The tool may use your inputs to train models or retain them, affecting confidentiality"], answer:3, explain:"<strong>The tool may use your inputs to train models or retain them, affecting confidentiality</strong> is exactly why you must understand data handling before sharing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reading policies makes the tool respond faster</b>: policies do not affect speed.</span><span class='qd'><b>Policies change the AI's writing style</b>: data policies do not alter writing style.</span><span class='qd'><b>It is required to unlock premium fonts</b>: this is unrelated to privacy review.</span>" },
{ id:"D2-085", domain:2, obj:"2.5", diff:"hard", q:"A healthcare worker needs AI help drafting patient communications. Which approach BEST balances usefulness and privacy/security?", options:["Use an organization-approved, compliant AI tool and avoid unnecessary identifiable details","Use any free tool and include full patient records for context","Disable all security to make it easier","Share records with coworkers publicly to crowdsource"], answer:0, explain:"<strong>Use an organization-approved, compliant AI tool and avoid unnecessary identifiable details</strong> respects patient privacy and regulatory obligations while still benefiting from AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use any free tool and include full patient records for context</b>: this exposes protected health information inappropriately.</span><span class='qd'><b>Disable all security to make it easier</b>: weakening security heightens the risk of a breach.</span><span class='qd'><b>Share records with coworkers publicly to crowdsource</b>: public sharing of records violates privacy.</span>" },
{ id:"D2-086", domain:2, obj:"2.5", diff:"medium", q:"Which of these is a good habit for protecting sensitive information when using AI chatbots?", options:["Include passwords so the AI can log in for you","Assume anything you type could be stored, and share only what is necessary","Paste full credit card numbers for convenience","Share other people's private data freely"], answer:1, explain:"<strong>Assume anything you type could be stored, and share only what is necessary</strong> is a sound data-minimization habit that limits exposure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Include passwords so the AI can log in for you</b>: sharing credentials is a serious security risk.</span><span class='qd'><b>Paste full credit card numbers for convenience</b>: exposing payment data invites fraud.</span><span class='qd'><b>Share other people's private data freely</b>: disclosing others' data without cause breaches privacy.</span>" },
{ id:"D2-087", domain:2, obj:"2.5", diff:"hard", q:"An analyst realizes the free AI tool they used may retain and reuse submitted text, and they had pasted client contact details. What is the MOST responsible next action?", options:["Ignore it since the text is already submitted","Paste even more data to test the tool","Report the potential data exposure per company policy and stop using that tool for sensitive data","Tell no one to avoid trouble"], answer:2, explain:"<strong>Report the potential data exposure per company policy and stop using that tool for sensitive data</strong> is the correct incident-response step to contain and address a possible breach.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore it since the text is already submitted</b>: ignoring a possible breach violates responsibility and policy.</span><span class='qd'><b>Paste even more data to test the tool</b>: adding data worsens the exposure.</span><span class='qd'><b>Tell no one to avoid trouble</b>: concealing an incident is unethical and often against policy.</span>" },
{ id:"D2-088", domain:2, obj:"2.5", diff:"easy", q:"Which type of information should you generally AVOID entering into a public AI chatbot?", options:["A request to define a common word","A question about general history","A prompt to suggest a synonym","Passwords, financial account numbers, and other people's personal data"], answer:3, explain:"<strong>Passwords, financial account numbers, and other people's personal data</strong> are exactly the sensitive items to keep out of public tools.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A request to define a common word</b>: this contains no sensitive data.</span><span class='qd'><b>A question about general history</b>: general knowledge questions pose no privacy risk.</span><span class='qd'><b>A prompt to suggest a synonym</b>: word help is harmless to share.</span>" },
{ id:"D2-089", domain:2, obj:"2.5", diff:"medium", q:"A teacher wants to use AI to give feedback on student essays. Which practice BEST protects student privacy?", options:["Remove student names and identifying details before submitting the text","Include full names, IDs, and home addresses","Post the essays publicly online for feedback","Add each student's medical information for context"], answer:0, explain:"<strong>Remove student names and identifying details before submitting the text</strong> minimizes exposure of minors' personal information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Include full names, IDs, and home addresses</b>: this needlessly exposes sensitive student data.</span><span class='qd'><b>Post the essays publicly online for feedback</b>: public posting risks students' privacy.</span><span class='qd'><b>Add each student's medical information for context</b>: medical data is highly sensitive and should not be shared.</span>" },
{ id:"D2-090", domain:2, obj:"2.5", diff:"hard", q:"When is disclosing AI use MOST clearly warranted?", options:["When suggesting a color for a personal doodle","When AI-generated material is presented as authoritative advice people will act on","When using AI to unscramble a word puzzle for fun","When asking AI to rhyme two words privately"], answer:1, explain:"<strong>When AI-generated material is presented as authoritative advice people will act on</strong> is when disclosure matters most, because people's decisions depend on knowing the source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>When suggesting a color for a personal doodle</b>: a private, trivial use needs no disclosure.</span><span class='qd'><b>When using AI to unscramble a word puzzle for fun</b>: a casual game has no audience to inform.</span><span class='qd'><b>When asking AI to rhyme two words privately</b>: private, low-stakes help does not require disclosure.</span>" },
{ id:"D2-091", domain:2, obj:"2.5", diff:"medium", q:"Which choice reduces SECURITY risk when integrating AI into a business workflow?", options:["Let every employee use random unvetted tools with sensitive data","Store all outputs on unsecured public links","Use enterprise tools with access controls and data-handling agreements","Disable authentication for convenience"], answer:2, explain:"<strong>Use enterprise tools with access controls and data-handling agreements</strong> lowers security risk through governance and protection of data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let every employee use random unvetted tools with sensitive data</b>: unvetted tools create uncontrolled exposure.</span><span class='qd'><b>Store all outputs on unsecured public links</b>: public storage invites unauthorized access.</span><span class='qd'><b>Disable authentication for convenience</b>: removing authentication weakens security.</span>" },
{ id:"D2-092", domain:2, obj:"2.5", diff:"easy", q:"A colleague suggests entering a coworker's private health note into a chatbot to 'help word a reply.' What should you do?", options:["Do it since it saves time","Add more of the coworker's details for accuracy","Share it in a group chat too","Decline and avoid sharing another person's private health information"], answer:3, explain:"<strong>Decline and avoid sharing another person's private health information</strong> respects that individual's privacy and likely legal protections.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Do it since it saves time</b>: convenience does not justify exposing someone's private health data.</span><span class='qd'><b>Add more of the coworker's details for accuracy</b>: adding details increases the privacy violation.</span><span class='qd'><b>Share it in a group chat too</b>: wider sharing compounds the breach.</span>" },
{ id:"D2-093", domain:2, obj:"2.5", diff:"hard", q:"A company allows AI use but requires employees to keep confidential data out of public tools. An employee anonymizes a dataset first but a few real names remain. What is the BEST correction?", options:["Fully remove or mask all identifiers before using the tool","Proceed anyway since most names were removed","Add the missing names back for completeness","Assume partial anonymization is always sufficient"], answer:0, explain:"<strong>Fully remove or mask all identifiers before using the tool</strong> is required because even a few remaining identifiers can expose individuals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Proceed anyway since most names were removed</b>: remaining names still create a real privacy exposure.</span><span class='qd'><b>Add the missing names back for completeness</b>: this defeats the purpose of anonymization.</span><span class='qd'><b>Assume partial anonymization is always sufficient</b>: partial masking can still identify people and is not reliably sufficient.</span>" },
{ id:"D2-094", domain:2, obj:"2.5", diff:"medium", q:"Why is caution warranted before trusting an AI tool that claims your data is 'never stored'?", options:["Storage claims change the AI's grammar","Claims should be verified against the actual terms and the tool's track record","Verifying wastes time and adds no value","All tools legally must store data"], answer:1, explain:"<strong>Claims should be verified against the actual terms and the tool's track record</strong> because marketing statements may not match real data practices.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Storage claims change the AI's grammar</b>: data handling has nothing to do with grammar.</span><span class='qd'><b>Verifying wastes time and adds no value</b>: verification is essential for protecting sensitive data.</span><span class='qd'><b>All tools legally must store data</b>: there is no universal rule requiring storage.</span>" },
{ id:"D2-095", domain:2, obj:"2.5", diff:"hard", q:"An organization is drafting an AI acceptable-use policy. Which element MOST directly protects privacy and security?", options:["A list of the CEO's favorite AI features","A ban on using spell-check","Rules on what data may be entered into which approved tools","A requirement to change the app's theme weekly"], answer:2, explain:"<strong>Rules on what data may be entered into which approved tools</strong> directly governs data exposure, the heart of privacy and security in AI use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A list of the CEO's favorite AI features</b>: preferences do not protect data.</span><span class='qd'><b>A ban on using spell-check</b>: this is unrelated to privacy or security.</span><span class='qd'><b>A requirement to change the app's theme weekly</b>: cosmetic rules do not safeguard data.</span>" },
{ id:"D2-096", domain:2, obj:"2.5", diff:"medium", q:"Which scenario shows appropriate CAUTION rather than over-restriction?", options:["Refusing to let AI suggest a single synonym","Banning AI for brainstorming harmless ideas","Blocking AI from defining common words","Using AI to draft a public blog post but not to process customers' payment data"], answer:3, explain:"<strong>Using AI to draft a public blog post but not to process customers' payment data</strong> shows sensible, risk-based caution: allow low-risk uses, restrict sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Refusing to let AI suggest a single synonym</b>: this over-restricts a harmless task.</span><span class='qd'><b>Banning AI for brainstorming harmless ideas</b>: brainstorming is low-risk and need not be banned.</span><span class='qd'><b>Blocking AI from defining common words</b>: defining words poses no risk and should not be blocked.</span>" },
{ id:"D2-097", domain:2, obj:"2.5", diff:"easy", q:"A safe default when unsure whether data is sensitive is to:", options:["Treat it as sensitive and avoid entering it into public tools until confirmed","Assume it is fine and share it everywhere","Enter it and hope for the best","Post it publicly to test reactions"], answer:0, explain:"<strong>Treat it as sensitive and avoid entering it into public tools until confirmed</strong> is a prudent, protective default when classification is unclear.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is fine and share it everywhere</b>: assuming safety risks exposing protected data.</span><span class='qd'><b>Enter it and hope for the best</b>: hoping is not a responsible data-handling practice.</span><span class='qd'><b>Post it publicly to test reactions</b>: public posting could cause an irreversible breach.</span>" },
{ id:"D2-098", domain:2, obj:"2.5", diff:"hard", q:"A vendor's AI note-taker records and transcribes meetings. Which privacy step is MOST important before deploying it?", options:["Pick the transcript's font before the meeting","Inform participants and obtain any required consent for recording and transcription","Ensure the recording uses bright colors","Make the transcript as long as possible"], answer:1, explain:"<strong>Inform participants and obtain any required consent for recording and transcription</strong> respects privacy rights and often legal requirements around recording.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pick the transcript's font before the meeting</b>: font choice is irrelevant to privacy.</span><span class='qd'><b>Ensure the recording uses bright colors</b>: color has no bearing on consent or privacy.</span><span class='qd'><b>Make the transcript as long as possible</b>: length does not address the consent requirement.</span>" },
{ id:"D2-099", domain:2, obj:"2.5", diff:"medium", q:"Why is it important to know whether an AI tool sends your data to third parties?", options:["Third parties improve the AI's spelling","Sharing data speeds up your internet","Third-party sharing can expand who can access your data and increase breach risk","It determines the AI's icon color"], answer:2, explain:"<strong>Third-party sharing can expand who can access your data and increase breach risk</strong>, so understanding data flow is key to protecting information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Third parties improve the AI's spelling</b>: data sharing does not affect spelling quality.</span><span class='qd'><b>Sharing data speeds up your internet</b>: it has no effect on connection speed.</span><span class='qd'><b>It determines the AI's icon color</b>: icon appearance is unrelated to data sharing.</span>" },
{ id:"D2-100", domain:2, obj:"2.5", diff:"hard", q:"An employee must choose between a convenient consumer chatbot and a slower enterprise tool for handling regulated customer data. Which reasoning is MOST responsible?", options:["Choose the consumer tool because it is faster","Pick whichever has a nicer interface","Use both simultaneously to compare outputs with real data","Prefer the enterprise tool because its data protections and compliance outweigh convenience for regulated data"], answer:3, explain:"<strong>Prefer the enterprise tool because its data protections and compliance outweigh convenience for regulated data</strong> correctly prioritizes privacy, security, and compliance over speed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Choose the consumer tool because it is faster</b>: speed does not justify risking regulated data.</span><span class='qd'><b>Pick whichever has a nicer interface</b>: interface aesthetics are irrelevant to data protection.</span><span class='qd'><b>Use both simultaneously to compare outputs with real data</b>: feeding regulated data into a consumer tool creates the exact exposure to avoid.</span>" }
);
